package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.io.StringWriter;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class JsonElementTest {

  @Test
  void toString_returnsJsonString_whenNoException() throws IOException {
    // Arrange
    JsonElement element = new JsonElement() {
      @Override
      public JsonElement deepCopy() {
        return null;
      }
    };

    StringWriter mockStringWriter = mock(StringWriter.class);
    JsonWriter mockJsonWriter = mock(JsonWriter.class);

    // Use MockedStatic for Streams.write
    try (MockedStatic<Streams> streamsMockedStatic = Mockito.mockStatic(Streams.class)) {
      streamsMockedStatic.when(() -> Streams.write(element, mockJsonWriter)).thenAnswer(invocation -> null);

      // Spy StringWriter and JsonWriter creation via reflection
      JsonElement elementSpy = Mockito.spy(element);

      // Because toString() creates new StringWriter and JsonWriter internally,
      // we cannot inject mocks directly.
      // Instead, we test the real toString() method for a simple subclass.

      // Act
      String result = element.toString();

      // Assert
      assertNotNull(result);
      assertFalse(result.isEmpty());
    }
  }

  @Test
  void toString_throwsAssertionError_whenIOExceptionOccurs() throws IOException {
    JsonElement element = new JsonElement() {
      @Override
      public JsonElement deepCopy() {
        return null;
      }
    };

    // Mock Streams.write to throw IOException
    try (MockedStatic<Streams> streamsMockedStatic = Mockito.mockStatic(Streams.class)) {
      streamsMockedStatic.when(() -> Streams.write(any(JsonElement.class), any(JsonWriter.class)))
          .thenThrow(new IOException("mock IOException"));

      // Act & Assert
      AssertionError thrown = assertThrows(AssertionError.class, element::toString);
      assertTrue(thrown.getCause() instanceof IOException);
      assertEquals("mock IOException", thrown.getCause().getMessage());
    }
  }
}
